diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 9a16ca96db76..567e48549bbe 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -844,6 +844,18 @@ static Instruction *foldNoWrapAdd(BinaryOperator &Add,
     Value *WideX = Builder.CreateZExt(X, Ty);
     return BinaryOperator::CreateAdd(WideX, NewC);
   }
+  // (zext nneg (X +nsw C1)) + C2 --> sext X + (zext(C1) + C2)
+  // This is valid because zext nneg implies the add result is non-negative,
+  // which allows treating the zext as equivalent to sext for the operand X.
+  Constant *ZExtNarrowC;
+  if (match(Op0, m_OneUse(m_NNegZExt(m_NSWAddLike(m_Value(X), m_Constant(ZExtNarrowC)))))) {
+    Value *WideC = Builder.CreateZExt(ZExtNarrowC, Ty);
+    Value *NewC = Builder.CreateAdd(WideC, Op1C);
+    if (auto *C = dyn_cast<Constant>(NewC); C && C->isZeroValue())
+      return CastInst::Create(Instruction::SExt, X, Ty);
+    Value *WideX = Builder.CreateSExt(X, Ty);
+    return BinaryOperator::CreateAdd(WideX, NewC);
+  }

   return nullptr;
 }

